18: package org.apache.kafka.metadata.authorizer;
19: 
20: import org.apache.kafka.common.Endpoint;
21: import org.apache.kafka.common.Uuid;
22: import org.apache.kafka.common.acl.AclBinding;
23: import org.apache.kafka.common.acl.AclBindingFilter;
24: import org.apache.kafka.common.errors.NotControllerException;
25: import org.apache.kafka.common.errors.TimeoutException;
26: import org.apache.kafka.common.metrics.Gauge;
27: import org.apache.kafka.common.metrics.Monitorable;
28: import org.apache.kafka.common.metrics.PluginMetrics;
29: import org.apache.kafka.common.metrics.Sensor;
30: import org.apache.kafka.common.metrics.stats.Rate;
31: import org.apache.kafka.common.metrics.stats.WindowedCount;
32: import org.apache.kafka.common.utils.SecurityUtils;
33: import org.apache.kafka.server.authorizer.Action;
34: import org.apache.kafka.server.authorizer.AuthorizableRequestContext;
35: import org.apache.kafka.server.authorizer.AuthorizationResult;
36: import org.apache.kafka.server.authorizer.AuthorizerServerInfo;
37: 
38: import java.io.IOException;
39: import java.util.ArrayList;
40: import java.util.HashMap;
41: import java.util.HashSet;
42: import java.util.LinkedHashMap;
43: import java.util.List;
44: import java.util.Map;
45: import java.util.Set;
46: import java.util.concurrent.CompletableFuture;
47: import java.util.concurrent.CompletionStage;
48: import java.util.concurrent.TimeUnit;
49: 
50: import static org.apache.kafka.server.authorizer.AuthorizationResult.ALLOWED;
51: import static org.apache.kafka.server.authorizer.AuthorizationResult.DENIED;
52: 
53: 
54: /**
55:  * Built-in authorizer implementation that stores ACLs in the metadata log.
56:  */
57: public class StandardAuthorizer implements ClusterMetadataAuthorizer, Monitorable {
58:     public static final String SUPER_USERS_CONFIG = "super.users";
59: 
60:     public static final String ALLOW_EVERYONE_IF_NO_ACL_IS_FOUND_CONFIG = "allow.everyone.if.no.acl.found";
61: 
62:     /**
63:      * A future which is completed once we have loaded up to the initial high watermark.
64:      */
65:     private final CompletableFuture<Void> initialLoadFuture = new CompletableFuture<>();
66: 
67:     /**
68:      * The current data. We use a read-write lock to synchronize reads and writes to the data. We
69:      * expect one writer and multiple readers accessing the ACL data, and we use the lock to make
70:      * sure we have consistent reads when writer tries to change the data.
71:      */
72:     private volatile StandardAuthorizerData data = StandardAuthorizerData.createEmpty();
73: 
74:     private AuthorizerMetrics authorizerMetrics;
75: 
76:     @Override
77:     public void setAclMutator(AclMutator aclMutator) {
78:         this.data = data.copyWithNewAclMutator(aclMutator);
79:     }
80: 
81:     @Override
82:     public AclMutator aclMutatorOrException() {
83:         AclMutator aclMutator = data.aclMutator;
84:         if (aclMutator == null) {
85:             throw new NotControllerException("The current node is not the active controller.");
86:         }
87:         return aclMutator;
88:     }
89: 
90:     @Override
91:     public void completeInitialLoad() {
92:         data = data.copyWithNewLoadingComplete(true);
93:         data.log.info("Completed initial ACL load process.");
94:         initialLoadFuture.complete(null);
95:     }
96: 
97:     // Visible for testing
98:     public CompletableFuture<Void> initialLoadFuture() {
99:         return initialLoadFuture;
100:     }
101: 
102:     @Override
103:     public void completeInitialLoad(Exception e) {
104:         if (!initialLoadFuture.isDone()) {
105:             data.log.error("Failed to complete initial ACL load process.", e);
106:             initialLoadFuture.completeExceptionally(e);
107:         }
108:     }
109: 
110:     @Override
111:     public void addAcl(Uuid id, StandardAcl acl) {
112:         data.addAcl(id, acl);
113:     }
114: 
115:     @Override
116:     public void removeAcl(Uuid id) {
117:         data.removeAcl(id);
118:     }
119: 
120:     @Override
121:     public void loadSnapshot(Map<Uuid, StandardAcl> acls) {
122:         StandardAuthorizerData newData = StandardAuthorizerData.createEmpty();
123:         for (Map.Entry<Uuid, StandardAcl> entry : acls.entrySet()) {
124:             newData.addAcl(entry.getKey(), entry.getValue());
125:         }
126:         data = data.copyWithNewAcls(newData.getAclCache());
127:     }
128: 
129:     @Override
130:     public Map<Endpoint, ? extends CompletionStage<Void>> start(
131:             AuthorizerServerInfo serverInfo) {
132:         Map<Endpoint, CompletableFuture<Void>> result = new HashMap<>();
133:         for (Endpoint endpoint : serverInfo.endpoints()) {
134:             if (serverInfo.earlyStartListeners().contains(
135:                     endpoint.listener())) {
136:                 result.put(endpoint, CompletableFuture.completedFuture(null));
137:             } else {
138:                 result.put(endpoint, initialLoadFuture);
139:             }
140:         }
141:         return result;
142:     }
143: 
144:     @Override
145:     public List<AuthorizationResult> authorize(
146:             AuthorizableRequestContext requestContext,
147:             List<Action> actions) {
148:         List<AuthorizationResult> results = new ArrayList<>(actions.size());
149:         StandardAuthorizerData curData = data;
150:         for (Action action : actions) {
151:             AuthorizationResult result = curData.authorize(requestContext, action);
152:             results.add(result);
153:             authorizerMetrics.recordAuthorizerMetrics(result);
154:         }
155:         return results;
156:     }
157: 
158:     @Override
159:     public Iterable<AclBinding> acls(AclBindingFilter filter) {
160:         // The Iterable returned here is consistent because it is created over a read-only
161:         // copy of ACLs data.
162:         return data.acls(filter);
163:     }
164: 
165:     @Override
166:     public int aclCount() {
167:         return data.aclCount();
168:     }
169: 
170:     @Override
171:     public void close() throws IOException {
172:         // Complete the initialLoadFuture, if it hasn't been completed already.
173:         initialLoadFuture.completeExceptionally(new TimeoutException("The authorizer was " +
174:             "closed before the initial load could complete."));
175:     }
176: 
177:     @Override
178:     public void configure(Map<String, ?> configs) {
179:         Set<String> superUsers = getConfiguredSuperUsers(configs);
180:         AuthorizationResult defaultResult = getDefaultResult(configs);
181:         int nodeId;
182:         try {
183:             nodeId = Integer.parseInt(configs.get("node.id").toString().trim());
184:         } catch (Exception e) {
185:             nodeId = -1;
186:         }
187:         data = data.copyWithNewConfig(nodeId, superUsers, defaultResult);
188:         this.data.log.info("set super.users={}, default result={}", String.join(",", superUsers), defaultResult);
189:     }
190: 
191:     // VisibleForTesting
192:     Set<String> superUsers()  {
193:         return new HashSet<>(data.superUsers());
194:     }
195: 
196:     AuthorizationResult defaultResult() {
197:         return data.defaultResult();
198:     }
199: 
200:     static Set<String> getConfiguredSuperUsers(Map<String, ?> configs) {
201:         Object configValue = configs.get(SUPER_USERS_CONFIG);
202:         if (configValue == null) return Set.of();
203:         String[] values = configValue.toString().split(";");
204:         Set<String> result = new HashSet<>();
205:         for (String value : values) {
206:             String v = value.trim();
207:             if (!v.isEmpty()) {
208:                 SecurityUtils.parseKafkaPrincipal(v);
209:                 result.add(v);
210:             }
211:         }
212:         return result;
213:     }
214: 
215:     static AuthorizationResult getDefaultResult(Map<String, ?> configs) {
216:         Object configValue = configs.get(ALLOW_EVERYONE_IF_NO_ACL_IS_FOUND_CONFIG);
217:         if (configValue == null) return DENIED;
218:         return Boolean.parseBoolean(configValue.toString().trim()) ? ALLOWED : DENIED;
219:     }
220: 
221:     @Override
222:     public void withPluginMetrics(PluginMetrics metrics) {
223:         this.authorizerMetrics = new AuthorizerMetrics(metrics);
224:     }
225: 
226:     private class AuthorizerMetrics {
227:         private final Sensor authorizationAllowedSensor;
228:         private final Sensor authorizationDeniedSensor;
229:         private final Sensor authorizationRequestSensor;
230: 
231:         private AuthorizerMetrics(PluginMetrics metrics) {
232:             authorizationAllowedSensor = metrics.addSensor("authorizer-authorization-allowed");
233:             authorizationAllowedSensor.add(
234:                     metrics.metricName("authorization-allowed-rate-per-minute", "The number of authorization allowed per minute", new LinkedHashMap<>()),
235:                     new Rate(TimeUnit.MINUTES, new WindowedCount()));
236: 
237:             authorizationDeniedSensor = metrics.addSensor("authorizer-authorization-denied");
238:             authorizationDeniedSensor.add(
239:                     metrics.metricName("authorization-denied-rate-per-minute", "The number of authorization denied per minute", new LinkedHashMap<>()),
240:                     new Rate(TimeUnit.MINUTES, new WindowedCount()));
241: 
242:             authorizationRequestSensor = metrics.addSensor("authorizer-authorization-request");
243:             authorizationRequestSensor.add(
244:                     metrics.metricName("authorization-request-rate-per-minute", "The number of authorization request per minute", new LinkedHashMap<>()),
245:                     new Rate(TimeUnit.MINUTES, new WindowedCount()));
246: 
247:             metrics.addMetric(
248:                     metrics.metricName("acls-total-count", "The number of acls defined", new LinkedHashMap<>()),
249:                     (Gauge<Integer>) (config, now) -> aclCount());
250:         }
251: 
252:         private void recordAuthorizerMetrics(AuthorizationResult authorizationResult) {
253:             if (authorizationResult == ALLOWED) {
254:                 authorizationAllowedSensor.record();
255:             } else {
256:                 authorizationDeniedSensor.record();
257:             }
258:             authorizationRequestSensor.record();
259:         }
260:     }
261: }
