18: package org.apache.kafka.server.authorizer;
19: 
20: import org.apache.kafka.common.acl.AclOperation;
21: import org.apache.kafka.common.resource.ResourcePattern;
22: 
23: import java.util.Objects;
24: 
25: public class Action {
26: 
27:     private final ResourcePattern resourcePattern;
28:     private final AclOperation operation;
29:     private final int resourceReferenceCount;
30:     private final boolean logIfAllowed;
31:     private final boolean logIfDenied;
32: 
33:     /**
34:      * @param operation non-null operation being performed
35:      * @param resourcePattern non-null resource pattern on which this action is being performed
36:      */
37:     public Action(AclOperation operation,
38:                   ResourcePattern resourcePattern,
39:                   int resourceReferenceCount,
40:                   boolean logIfAllowed,
41:                   boolean logIfDenied) {
42:         this.operation = Objects.requireNonNull(operation, "operation can't be null");
43:         this.resourcePattern = Objects.requireNonNull(resourcePattern, "resourcePattern can't be null");
44:         this.logIfAllowed = logIfAllowed;
45:         this.logIfDenied = logIfDenied;
46:         this.resourceReferenceCount = resourceReferenceCount;
47:     }
48: 
49:     /**
50:      * @return a non-null resource pattern on which this action is being performed
51:      */
52:     public ResourcePattern resourcePattern() {
53:         return resourcePattern;
54:     }
55: 
56:     /**
57:      *
58:      * @return a non-null operation being performed
59:      */
60:     public AclOperation operation() {
61:         return operation;
62:     }
63: 
64:     /**
65:      * Indicates if audit logs tracking ALLOWED access should include this action if result is
66:      * ALLOWED. The flag is true if access to a resource is granted while processing the request as a
67:      * result of this authorization. The flag is false only for requests used to describe access where
68:      * no operation on the resource is actually performed based on the authorization result.
69:      */
70:     public boolean logIfAllowed() {
71:         return logIfAllowed;
72:     }
73: 
74:     /**
75:      * Indicates if audit logs tracking DENIED access should include this action if result is
76:      * DENIED. The flag is true if access to a resource was explicitly requested and request
77:      * is denied as a result of this authorization request. The flag is false if request was
78:      * filtering out authorized resources (e.g. to subscribe to regex pattern). The flag is also
79:      * false if this is an optional authorization where an alternative resource authorization is
80:      * applied if this fails (e.g. Cluster:Create which is subsequently overridden by Topic:Create).
81:      */
82:     public boolean logIfDenied() {
83:         return logIfDenied;
84:     }
85: 
